import React, { useState } from "react";
import { Container, ButtonGroup, Button } from "react-bootstrap";

const experiences = [
  {
    id: 1,
    title: "Responsable du secteur arbitrage – Handball Club Cournon d’Auvergne",
    date: "Depuis septembre 2024",
    description: "Chargé de la stratégie ...",
    domain: "autres",
  },
  {
    id: 2,
    title: "Co-fondateur – Micro-entreprise YTNS",
    date: "Depuis février 2025",
    description: "Création d’une micro-entreprise ...",
    domain: "informatique",
  },
  // Ajoute ici les autres expériences comme dans ton fichier, avec `domain: "informatique"` ou `domain: "autres"`
];

function Experience() {
  const [filter, setFilter] = useState("all");

  const filteredExperiences =
    filter === "all"
      ? experiences
      : experiences.filter((exp) => exp.domain === filter);

  return (
    <section id="experience" className="py-5">
      <Container>
        <h2 className="mb-4">Expériences Professionnelles</h2>

        <ButtonGroup className="mb-4">
          <Button
            variant={filter === "informatique" ? "primary" : "outline-primary"}
            onClick={() => setFilter("informatique")}
          >
            Informatique
          </Button>
          <Button
            variant={filter === "autres" ? "primary" : "outline-primary"}
            onClick={() => setFilter("autres")}
          >
            Autres domaines
          </Button>
          <Button
            variant={filter === "all" ? "primary" : "outline-secondary"}
            onClick={() => setFilter("all")}
          >
            Tous
          </Button>
        </ButtonGroup>

        {filteredExperiences.map((exp) => (
          <div key={exp.id} className={`experience-${exp.domain}`}>
            <h5>{exp.title}</h5>
            <p>
              <em>{exp.date}</em>
              <br />
              {exp.description}
            </p>
          </div>
        ))}
      </Container>
    </section>
  );
}

export default Experience;
